"use strict";function t(t,e="YYYY-MM-DD"){if(!t)return"";const a=new Date(t),r=a.getFullYear(),n=String(a.getMonth()+1).padStart(2,"0"),g=String(a.getDate()).padStart(2,"0"),o=String(a.getHours()).padStart(2,"0"),l=String(a.getMinutes()).padStart(2,"0"),u=String(a.getSeconds()).padStart(2,"0");return e.replace("YYYY",r).replace("MM",n).replace("DD",g).replace("HH",o).replace("mm",l).replace("ss",u)}exports.calculateTotal=function(t,e){return t.filter((t=>t.type===e)).reduce(((t,e)=>t+parseFloat(e.amount)),0)},exports.formatAmount=function(t){return(t/100).toFixed(2)},exports.formatDate=t,exports.getDateRange=function(e){const a=new Date;let r,n;switch(e){case"today":r=new Date(a.getFullYear(),a.getMonth(),a.getDate()),n=new Date(a.getFullYear(),a.getMonth(),a.getDate(),23,59,59);break;case"week":const t=a.getDay(),e=a.getDate()-t+(0===t?-6:1);r=new Date(a.getFullYear(),a.getMonth(),e),n=new Date(a.getFullYear(),a.getMonth(),e+6,23,59,59);break;default:r=new Date(a.getFullYear(),a.getMonth(),1),n=new Date(a.getFullYear(),a.getMonth()+1,0,23,59,59)}return{startDate:t(r),endDate:t(n)}};
